const rows = $input.all().map(i => i.json);
const STRIP = ['instagram','instagram_backup','tiktok','facebook','linkedin','youtube'];
const subs = rows.filter(r => r && r.id).map(r => {
  const a = (r.answers && typeof r.answers === 'object') ? Object.assign({}, r.answers) : {};
  STRIP.forEach(k => { delete a[k]; });
  return { id: r.id, slug: r.slug || '', first_name: r.first_name || '', last_name: r.last_name || '', email: r.email || '', ai_avatar: r.ai_avatar || '', status: r.status || '', created_at: r.created_at || '', answers: a };
});
return [{ json: { ok: true, count: subs.length, submissions: subs } }];
